const distributedMedias = $('GetMediaToDeliver').all().map(x => x["json"]);
const distributedGroup = $('GetGroupToDistribute').first().json;
const sentMsgId = $input.first().json.id
const values = distributedMedias.map(item => {
  const { Id } = item;
  return `(${Id}, '${distributedGroup["Link"]}', '${distributedGroup["Link"]}/${sentMsgId}' )`; // DISTRIBUTION LINK MUST BE COMBINED WITH THE ID OF Sent Msg
}).join(',\n');
const insertSQL = `
BEGIN TRANSACTION;

BEGIN TRY

  INSERT INTO XinhDistributionLog 
    (SourceId, DistributionTarget, DistributionLink) 
  VALUES ${values};

COMMIT TRANSACTION;
END TRY
BEGIN CATCH
    ROLLBACK TRANSACTION;
END CATCH;
`
return {
  query: insertSQL.replace(/\s+/g, ' ').trim()
}

